#!/usr/bin/env python3
"""获取宏观经济数据"""
import sys
import json
import akshare as ak

def get_macro_data(indicator="gdp"):
    """获取宏观经济指标"""
    try:
        indicators = {
            "gdp": ("GDP", ak.macro_china_gdp),
            "cpi": ("CPI通胀", ak.macro_china_cpi),
            "pmi": ("PMI采购经理指数", ak.macro_china_pmi),
            "m2": ("M2货币供应", ak.macro_china_m2),
        }

        if indicator not in indicators:
            return {"error": f"Unknown indicator: {indicator}"}

        name, func = indicators[indicator]
        df = func()

        # 获取最新数据
        latest = df.iloc[-1]
        return {
            "indicator": indicator,
            "name": name,
            "date": str(latest.iloc[0]),
            "value": float(latest.iloc[1]) if len(latest) > 1 else None
        }
    except Exception as e:
        return {"error": str(e)}

def get_macro_summary():
    """获取宏观经济概览"""
    try:
        result = {}
        for ind in ["gdp", "cpi", "pmi", "m2"]:
            data = get_macro_data(ind)
            if "error" not in data:
                result[ind] = {
                    "value": data.get("value"),
                    "date": data.get("date")
                }
        return result
    except Exception as e:
        return {"error": str(e)}

if __name__ == "__main__":
    if len(sys.argv) > 1:
        cmd = sys.argv[1]
        if cmd == "data":
            indicator = sys.argv[2] if len(sys.argv) > 2 else "gdp"
            result = get_macro_data(indicator)
        elif cmd == "summary":
            result = get_macro_summary()
        else:
            result = {"error": f"Unknown command: {cmd}"}
    else:
        result = {"usage": "python macro.py data <indicator> | summary"}

    print(json.dumps(result, ensure_ascii=False, indent=2))
# --- File: stock_price.py ---
#!/usr/bin/env python3
"""获取股票实时价格和K线数据"""
import sys
import json
import akshare as ak

def get_stock_price(symbol, period="daily", start_date=None):
    """获取股票价格"""
    try:
        df = ak.stock_zh_kline(
            symbol=symbol,
            period=period,
            adjust="qfq",
            start_date=start_date
        )
        latest = df.iloc[-1]
        return {
            "symbol": symbol,
            "date": str(latest['date']),
            "open": float(latest['open']),
            "high": float(latest['high']),
            "low": float(latest['low']),
            "close": float(latest['close']),
            "volume": int(latest['volume']),
            "pct_chg": float(latest['pct_chg'])
        }
    except Exception as e:
        return {"error": str(e)}

def get_market_overview():
    """获取大盘概览"""
    try:
        df = ak.stock_zh_a_spot_em()
        # 涨跌幅排行
        top_gainers = df.nlargest(5, '涨跌幅')[['代码', '名称', '涨跌幅']].to_dict('records')
        top_losers = df.nsmallest(5, '涨跌幅')[['代码', '名称', '涨跌幅']].to_dict('records')
        return {
            "total_stocks": len(df),
            "top_gainers": top_gainers,
            "top_losers": top_losers
        }
    except Exception as e:
        return {"error": str(e)}

if __name__ == "__main__":
    if len(sys.argv) > 1:
        cmd = sys.argv[1]
        if cmd == "price":
            symbol = sys.argv[2] if len(sys.argv) > 2 else "000001"
            result = get_stock_price(symbol)
        elif cmd == "overview":
            result = get_market_overview()
        else:
            result = {"error": f"Unknown command: {cmd}"}
    else:
        result = {"usage": "python stock.py price <symbol> | overview"}

    print(json.dumps(result, ensure_ascii=False, indent=2))

