        else: insight_tip = f"✅ 使用率 <strong>{used_pct}%</strong>，整体处于健康合理区间。"
    else:
        insight_tip = "📎 当前周期内未找到有效数据，请确认时间范围或业务产生情况。"

    return f"""<!DOCTYPE html>
<html lang="zh-CN">
<head>
