</style>
</head>
<body>

<div class="hero">
  <div class="hero-title">📊 {metric_label} · 大屏分析看板</div>
  <div class="hero-meta">
    <span class="hero-tag">🏢 业务系统: {system}</span>
    <span class="hero-tag">📅 时间范围: {start_date} ~ {end_date}</span>
    <span class="hero-tag">🕐 生成时间: {now_str}</span>
