    <span style="color:var(--c-muted)">—</span>
    <input type="date" id="i_end" value="{end_date}">
    <button class="btn-query" id="btn_q" onclick="doQuery()">🔍 实时加载数据</button>
    <span class="status-txt" id="status_msg"></span>
